import './Dialog.scss';

import { classNames } from ':helpers/classnames';
import React, { type FC, useCallback, useEffect } from 'react';

import { Modal } from '../Modal';
import type { DialogProps } from './Dialog.types';

export const Dialog: FC<DialogProps> = ({
	open = false,
	onClose,
	children,
	applicationRootElement,
	className,
	...rest
}) => {
	const handleEscClick = useCallback(
		(event: KeyboardEvent): void => {
			if (event.keyCode === 27 && onClose) {
				onClose(event);
			}
		},
		[onClose],
	);

	useEffect(() => {
		//Добавляем if, так как useCallback будет работать только если передаваемый onClose будет обернут в  useCallback. Иначе это бесполезно
		if (open) {
			document.addEventListener('keydown', handleEscClick, false);
		} else {
			document.removeEventListener('keydown', handleEscClick, false);
		}
		return () => {
			document.removeEventListener('keydown', handleEscClick, false);
		};
	}, [handleEscClick, open]);

	return (
		<Modal
			data-testid="Dialog"
			open={open}
			className={classNames('dsb_modal', open && 'dsb_modal__open')}
			applicationRootElement={applicationRootElement}
		>
			<div className={classNames('dsb_dialog', className)}>
				<div className="dsb_dialog-backdrop"></div>
				{children}
			</div>
		</Modal>
	);
};
